    int n, m;
    cin >> n >> m;

    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    memset(color, -1, sizeof(color));
    bool isBipartite = true;

    for (int i = 1; i <= n && isBipartite; ++i) {
        if (color[i] == -1) {
            isBipartite = bfs(i);
        }
    }

    if (!isBipartite) {
        cout << "-1\n";
        return;
    }

    vector<int> A, B;
