#include <iostream>
#include <vector>
#include <queue>
#include <set>

using namespace std;

int solve(int n, vector<vector<int>>& adj, vector<int>& indegree) {
    int reads = 0;
    set<int> understood;
    priority_queue<int, vector<int>, greater<int>> pq;

    // Initialize queue with nodes having zero in-degree
    for (int i = 0; i < n; ++i) {
        if (indegree[i] == 0) {
            pq.push(i);
        }
    }

    while (!pq.empty()) {
        int curr = pq.top();
        pq.pop();
        understood.insert(curr);

        for (int neighbor : adj[curr]) {
            if (understood.find(neighbor) != understood.end()) {
                continue;
            }
            --indegree[neighbor];
            if (indegree[neighbor] == 0) {
                pq.push(neighbor);
            }
        }

        // Check if we've read the entire book
        if ((int)understood.size() == n) {
            return reads + 1;
        }
    }

    // If we exit the loop without understanding all chapters, there's a cycle
    return -1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<vector<int>> adj(n);
        vector<int> indegree(n, 0);

        for (int i = 0; i < n; ++i) {
            int k;
            cin >> k;
            while (k--) {
                int x;
                cin >> x;
                --x; // Convert to 0-based index
                adj[x].push_back(i);
                ++indegree[i];
            }
        }

        cout << solve(n, adj, indegree) << '\n';
    }

    return 0;
}

