#include <iostream>
#include <queue>
#include <string>
using namespace std;

void solve(int n, int m, int k, const string& a, const string& b) {
    priority_queue<char, vector<char>, greater<char>> pq_a(a.begin(), a.end());
    priority_queue<char, vector<char>, greater<char>> pq_b(b.begin(), b.end());

    string c = "";
    int op_count_a = 0, op_count_b = 0;

    while (!pq_a.empty() || !pq_b.empty()) {
        char next_a = pq_a.empty() ? '\0' : pq_a.top();
        char next_b = pq_b.empty() ? '\0' : pq_b.top();

        if (next_a <= next_b && op_count_a < k) {
            c += next_a;
            pq_a.pop();
            op_count_a++;
            op_count_b = 0;
        } else {
            c += next_b;
            pq_b.pop();
            op_count_b++;
            op_count_a = 0;
        }
    }

    cout << c << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, m, k;
        cin >> n >> m >> k;
        string a, b;
        cin >> a >> b;
        solve(n, m, k, a, b);
    }

    return 0;
}

