const int MOD = 1000000007;
int n, h;
vector<int> a;

void solve() {
    vector<vector<long long>> dp(n+1, vector<long long>(h+1));
    dp[0][0] = 1;

    for (int i = 1; i <= n; ++i) {
        for (int j = 0; j <= h; ++j) {
            dp[i][j] = dp[i-1][j];
            if (j >= h - a[i-1]) {
                dp[i][j] += dp[i-1][j + (h - a[i-1])];
                dp[i][j] %= MOD;
            }
        }
    }

    cout << dp[n][0] << '\n';
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> h;
    a.resize(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
