#include <bits/stdc++.h>
using namespace std;

#define ll long long
#define pb push_back
#define mp make_pair
#define F first
#define S second
#define vi vector<int>
#define vl vector<ll>
#define pii pair<int, int>
#define pll pair<ll, ll>

const int N = 1e5 + 7;
int n, k, a[N];
vector<vector<int>> adj(N);
bool vis[N];

void dfs(int node, int parent, int &xor_sum) {
    xor_sum ^= a[node];
    for (int child : adj[node]) {
        if (child != parent && !vis[child]) {
            vis[child] = true;
            dfs(child, node, xor_sum);
        }
    }
}

string solve() {
    cin >> n >> k;
    for (int i = 1; i <= n; ++i) cin >> a[i];
    for (int i = 0; i < n - 1; ++i) {
        int u, v; cin >> u >> v;
        adj[u].pb(v); adj[v].pb(u);
    }

    memset(vis, false, sizeof(vis));
    int root_xor = 0;
    dfs(1, -1, root_xor);

    if (root_xor == 0) return "YES";

    // Try deleting each edge once
    bool possible = false;
    for (int i = 0; i < n - 1; ++i) {
        int u, v; cin >> u >> v;
        adj[u].erase(find(adj[u].begin(), adj[u].end(), v));
        adj[v].erase(find(adj[v].begin(), adj[v].end(), u));

        memset(vis, false, sizeof(vis));
        int new_xor = 0;
        dfs(1, -1, new_xor);

        if (new_xor == root_xor) {
            possible = true;
            break;
        }

        adj[u].pb(v); adj[v].pb(u);
    }

    return possible ? "YES" : "NO";
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr); cout.tie(nullptr);
    int t; cin >> t;
    while (t--) {
        cout << solve() << '\n';
    }
    return 0;
}

