ll kadane(const vector<int>& arr) {
    int n = arr.size();
    ll max_sum = INT_MIN;
    ll current_max = 0;
    for (int i = 0; i < n; ++i) {
        current_max += arr[i];
        if (current_max > max_sum) {
            max_sum = current_max;
        }
        if (current_max < 0) {
            current_max = 0;
        }
    }
    return max_sum;
}

vector<ll> solve(int n, int x, const vector<int>& a) {
    vector<vector<ll>> dp(n, vector<ll>(MAXK, INT_MIN));

    // Compute kadane for each starting point
    for (int start = 0; start < n; ++start) {
        vector<int> prefix_sums(n, 0);
        prefix_sums[start] = a[start];
        ll kadane_val = kadane(prefix_sums);
        dp[start][0] = kadane_val;

        for (int end = start + 1; end < n; ++end) {
            prefix_sums[end] = prefix_sums[end - 1] + a[end];
            kadane_val = kadane(prefix_sums);
            dp[start][0] = max(dp[start][0], kadane_val);
        }
    }

    // Fill DP table for k > 0
    for (int k = 1; k <= n; ++k) {
        for (int start = 0; start < n; ++start) {
            for (int end = start; end < n; ++end) {
                int length = end - start + 1;
                ll prefix_sum = prefix_sum(end) - prefix_sum(start - 1);
                ll best_kadane = kadane(a);
