void dfs(int u, int p) {
    for (int v : d[u]) {
        if (v == p) continue;
        parent[v][0] = u;
        dfs(v, u);
    }
}

int lca(int u, int v) {
    if (__builtin_popcount(u ^ v) == 1) return __builtin_ctz(u ^ v);
    int log = 31 - __builtin_clz(__gcd(u, v));
    return parent[u][log] & parent[v][log];
}

int dis(int u, int v) {
    int l = lca(u, v);
    return dis(l, u) + dis(l, v) - 2 * dis(l, l);
}

int solve() {
    for (int mask = 0; mask < (1 << n); ++mask) dp[mask] = INF;
    dp[0] = 0;

    vector<vector<int>> best(n, vector<int>(n, 0));

    for (int mask = 0; mask < (1 << n); ++mask) {
        int fixed_cost = 0;
        int variable_cost = 0;

        for (int i = 0; i < n; ++i) {
            if ((mask >> i) & 1) {
                fixed_cost += k;

                int min_dist = INF;
                for (int j = 0; j < n; ++j) {
                    if (!(mask >> j) & 1) {
                        int dist = dis(j, i);
                        if (dist < min_dist) {
                            min_dist = dist;
                            best[j][i] = i;
                        }
                    }
                }

                variable_cost += d[i] * min_dist;
            }
        }

        dp[mask] = fixed_cost + variable_cost;
    }

    int min_cost = INF;
    int min_mask = 0;

    for (int mask = 0; mask < (1 << n); ++mask) {
        if (dp[mask] < min_cost) {
            min_cost = dp[mask];
            min_mask = mask;
        }
    }

    cout << min_cost << endl;

    vector<int> ans(n);
    for (int i = 0; i < n; ++i) {
        if ((min_mask >> i) & 1) {
            ans[i] = i + 1;
        } else {
            ans[i] = best[i][i];
        }
    }

    for (int x : ans) cout << x << " ";
    cout << endl;

    return 0;
}

