int minShots(vector<int>& a) {
    int n = a.size();
    vector<int> shots(n);

    // Calculate shots needed for each section individually
    for (int i = 0; i < n; ++i) {
        shots[i] = (a[i] + 1) / 2;
    }

    // Sort sections based on their individual shot requirements
    sort(shots.begin(), shots.end());

    // Try to form pairs greedily
    int result = 0;
    for (int i = 0; i < n; ++i) {
        if (shots[i] > 0) {
            result += shots[i];
            --shots[i];
            if (i > 0 && shots[i - 1] > 0) {
                --shots[i - 1];
            } else if (i < n - 1 && shots[i + 1] > 0) {
                --shots[i + 1];
            }
        }
    }

    return result;
}

