    cin >> n;
    for (int i = 0; i < 10; ++i) {
        cin >> a[i];
    }

    // Initialize DP table
    memset(dp, 0, sizeof(dp));
    dp[0][0] = 1;

    // Fill DP table
    for (int pos = 1; pos <= n; ++pos) {
        for (int mask = 0; mask < (1 << 10); ++mask) {
            if (dp[pos-1][mask] == 0) continue;
            for (int d = 0; d < 10; ++d) {
                int new_mask = mask;
                if ((new_mask & (1 << d)) != 0 || a[d] > 0) {
                    new_mask |= (1 << d);
                }
                if (pos == 1 && d == 0) continue; // Skip leading zero
                dp[pos][new_mask] = (dp[pos][new_mask] + dp[pos-1][mask]) % MOD;
            }
        }
    }

    // Count valid numbers
    int ans = 0;
    for (int mask = 0; mask < (1 << 10); ++mask) {
        bool valid = true;
        for (int d = 0; d < 10; ++d) {
            if ((mask & (1 << d)) == 0 && a[d] > 0) {
                valid = false;
                break;
            }
        }
        if (valid) {
            ans = (ans + dp[n][mask]) % MOD;
        }
    }

    cout << ans << endl;
}

