struct Ramp {
    int xi, di, ti, pi;
    bool operator<(const Ramp& r) const { return xi < r.xi; }
};

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);

    int n, L; cin >> n >> L;
    vector<Ramp> ramps(n);
    for (int i = 0; i < n; ++i) {
        cin >> ramps[i].xi >> ramps[i].di >> ramps[i].ti >> ramps[i].pi;
    }

    sort(ramps.begin(), ramps.end());

    vector<int> dp(L + 1, INT_MAX);
    dp[0] = 0;
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    pq.emplace(0, -1);

    while (!pq.empty()) {
        auto [time, prev] = pq.top(); pq.pop();
        if (time > dp[ramps.back().xi]) continue;

        for (int i = 0; i < n; ++i) {
            const auto& r = ramps[i];
            if (prev >= 0 && r.pi > ramps[prev].pi) continue;
            if (r.xi - r.pi < 0) continue;

            int next_x = r.xi + r.di;
            long long next_time = time + (r.xi - r.pi) + r.ti + (next_x - r.xi);
            if (next_time < dp[next_x]) {
                dp[next_x] = next_time;
                pq.emplace(next_time, i);
            }
        }
    }

    cout << dp[L] << '\n';

    vector<int> path;
    for (int i = L; i >= 0; ) {
        for (int j = n - 1; j >= 0; --j) {
            const auto& r = ramps[j];
            int next_x = r.xi + r.di;
            if (i == next_x && dp[i] == dp[r.xi] + (r.xi - r.pi) + r.ti + (next_x - r.xi)) {
                path.push_back(j + 1);
                i = r.xi;
                break;
            }
        }
    }

    reverse(path.begin(), path.end());
    cout << path.size() << '\n';
    for (int p : path) cout << p << ' ';
    cout << '\n';

    return 0;
}

