bool isBeautiful(const vector<int>& a) {
    int n = a.size();
    if (n == 0) return false;

    // Find the first two distinct elements
    set<int> uniqueElements(a.begin(), a.end());
    if (uniqueElements.size() < 2) return true; // All elements are equal

    auto it = uniqueElements.begin();
    int a_i = *it++;
    int a_j = *it;

    // Check if every element is divisible by either a_i or a_j
    for (int x : a) {
        if (x % a_i != 0 && x % a_j != 0) return false;
    }

    return true;
}

