#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

bool canPartition(vector<int>& a) {
    int n = a.size();
    vector<int> odd, even;

    // Separate numbers by parity
    for (int x : a) {
        if (x % 2 == 0) even.push_back(x);
        else odd.push_back(x);
    }

    // If counts are unequal, impossible to pair
    if (odd.size() != even.size()) return false;

    // Sort both lists
    sort(odd.begin(), odd.end());
    sort(even.begin(), even.end());

    // Check if we can pair odd and even numbers
    for (size_t i = 0; i < odd.size(); ++i) {
        if (abs(odd[i] - even[i]) != 1) return false;
    }

    return true;
}

void solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) cin >> a[i];

    cout << (canPartition(a) ? "YES\n" : "NO\n");
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);
    int t;
    cin >> t;
    while (t--) solve();
    return 0;
}

