const int N = 8;
const int dx[] = {2, -2, 2, -2};
const int dy[] = {2, 2, -2, -2};

bool isValid(int x, int y, const vector<vector<char>>& board) {
    return x >= 0 && x < N && y >= 0 && y < N && board[x][y] != '#';
}

bool bfs(const vector<vector<char>>& board, pair<int, int> start1, pair<int, int> start2) {
    vector<vector<bool>> vis1(N, vector<bool>(N, false));
    vector<vector<bool>> vis2(N, vector<bool>(N, false));

    queue<pair<int, int>> q1, q2;
    q1.push(start1);
    q2.push(start2);
    vis1[start1.first][start1.second] = true;
    vis2[start2.first][start2.second] = true;

    while (!q1.empty() && !q2.empty()) {
        auto [cx1, cy1] = q1.front(); q1.pop();
        auto [cx2, cy2] = q2.front(); q2.pop();

        if (cx1 == cx2 && cy1 == cy2) {
            return true;
        }

        for (int i = 0; i < 4; ++i) {
            int nx1 = cx1 + dx[i], ny1 = cy1 + dy[i];
            if (isValid(nx1, ny1, board) && !vis1[nx1][ny1]) {
                q1.push({nx1, ny1});
                vis1[nx1][ny1] = true;
            }
            int nx2 = cx2 + dx[i], ny2 = cy2 + dy[i];
            if (isValid(nx2, ny2, board) && !vis2[nx2][ny2]) {
                q2.push({nx2, ny2});
                vis2[nx2][ny2] = true;
            }
        }
    }
    return false;
}

