    int t;
    cin >> t;
    while (t--) {
        vector<vector<char>> board(N, vector<char>(N));
        for (int i = 0; i < N; ++i) {
            string s;
            cin >> s;
            for (int j = 0; j < N; ++j) {
                board[i][j] = s[j];
            }
        }

        pair<int, int> pos1, pos2;
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                if (board[i][j] == 'K') {
                    if (pos1.first == -1) {
                        pos1 = {i, j};
                    } else {
                        pos2 = {i, j};
                    }
                }
            }
        }

