void solve() {
    int n, m;
    cin >> n >> m;
    vector<int> perm(n);
    for (int i = 0; i < n; ++i) {
        cin >> perm[i];
    }

    vector<vector<int>> swaps(m, vector<int>(2));
    for (int i = 0; i < m; ++i) {
        cin >> swaps[i][0] >> swaps[i][1];
    }

    // Sort swaps by starting position
    sort(swaps.begin(), swaps.end());

    // Priority queue to store available swaps
    priority_queue<pair<int, int>> pq;

    for (int pos = 0; pos < n; ++pos) {
        // Add all swaps that include the current position
        while (!swaps.empty() && swaps.front()[0] <= pos + 1) {
            pq.push({min(swaps.front()[0], swaps.front()[1]), max(swaps.front()[0], swaps.front()[1])});
            swaps.erase(swaps.begin());
        }

        // Find the maximum value among the current position and its neighbors within the available swaps
        int max_val = perm[pos];
        int best_swap = -1;
        for (auto& s : pq) {
            if (s.first == pos + 1 || s.second == pos + 1) {
                max_val = max(max_val, perm[s.first - 1]);
                best_swap = s.first;
                break;
            }
        }

        // Swap if needed
        if (best_swap != -1) {
            swap(perm[pos], perm[best_swap - 1]);
        }

        // Remove used swaps
        while (!pq.empty() && pq.top().first > pos + 1) {
            pq.pop();
        }
    }

    // Output the resulting permutation
    for (int i = 0; i < n; ++i) {
        cout << perm[i] << " ";
    }
    cout << endl;
}

