const int MOD = 1000000007;

// Function to compute Fibonacci numbers up to max_val
vector<int> fibonacci(int max_val) {
    vector<int> fib(max_val + 1);
    fib[0] = 0;
    fib[1] = 1;
    for (int i = 2; i <= max_val; ++i) {
        fib[i] = (fib[i - 1] + fib[i - 2]) % MOD;
    }
    return fib;
}

// Function to count valid pairs (a, b) such that s_a ∣ s_b = 2^i and s_a & s_b = 0
unordered_map<long long, int> countValidPairs(const vector<int>& s) {
    unordered_map<long long, int> counts;
    for (size_t i = 0; i < s.size(); ++i) {
        for (size_t j = 0; j < s.size(); ++j) {
            if ((s[i] | s[j]) == (s[i] & s[j])) continue;
            if ((s[i] & s[j]) != 0) continue;
            long long key = (long long)s[i] << 32 | s[j];
            counts[key]++;
        }
    }
    return counts;
}

