#define repr(i, a, b) for (int i = a; i >= b; --i)

const int mod = 1e9 + 7;
const int mxN = 1e5 + 5;

void solve() {
    int n;
    cin >> n;
    vi a(n);
    rep(i, 0, n) cin >> a[i];

    // Next greater element for each element in the original array
    vi ng(n, -1);
    stack<int> st;
    rep(i, 0, n) {
        while (!st.empty() && a[st.top()] < a[i]) {
            ng[st.top()] = i;
            st.pop();
        }
        st.push(i);
    }

    // Segment tree for range maximum query
    vector<int> seg(4 * n, 0);
    auto build = [&](auto self, int node, int l, int r) -> void {
        if (l == r) {
            seg[node] = a[l];
            return;
        }
        int mid = (l + r) / 2;
        self(self, 2 * node, l, mid);
        self(self, 2 * node + 1, mid + 1, r);
        seg[node] = max(seg[2 * node], seg[2 * node + 1]);
    };
    build(build, 1, 0, n - 1);

    auto query = [&](auto self, int node, int tl, int tr, int l, int r) -> int {
        if (l > r) return -1;
        if (tl == l && tr == r) return seg[node];
        int mid = (tl + tr) / 2;
        return max(self(self, 2 * node, tl, mid, l, min(mid, r)),
                   self(self, 2 * node + 1, mid + 1, tr, max(mid + 1, l), r));
    };

    // DP array to store the length of LIS ending at each position
    vi dp(n, 1);
    rep(i, 0, n) {
        int prev_max = query(query, 1, 0, n - 1, 0, ng[i] - 1);
        dp[i] = prev_max + 1;
    }

    // Result is the maximum value in the DP array
    cout << *max_element(dp.begin(), dp.end()) << '\n';
}

