#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

const int MOD = 1000000007;
const int MAXN = 1000000;

int n, m, k;
vector<int> adj[MAXN];
vector<pair<int, int>> edges;

void dfs(int u, vector<bool>& visited, vector<int>& layers) {
    stack<int> st;
    st.push(u);
    while (!st.empty()) {
        int v = st.top();
        st.pop();
        if (!visited[v]) {
            visited[v] = true;
            layers[v] = max(layers[v], layers[u]);
            for (int w : adj[v]) {
                if (!visited[w]) {
                    st.push(w);
                }
            }
        }
    }
}

long long powmod(long long base, int exp) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % MOD;
        }
        base = (base * base) % MOD;
        exp /= 2;
    }
    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> m >> k;

    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        edges.emplace_back(u, v);
    }

    vector<bool> visited(n + 1, false);
    vector<int> layers(n + 1, 0);

    for (int i = 1; i <= n; ++i) {
        if (!visited[i]) {
            dfs(i, visited, layers);
        }
    }

    vector<vector<long long>> dp(n + 1, vector<long long>(n + 1, 0));
    for (int j = 1; j <= n; ++j) {
        dp[0][j] = 1;
    }

    for (auto& e : edges) {
        int u = e.first, v = e.second;
        dp[v][v] = (dp[v][v] + dp[u][u]) % MOD;
        for (int l = u + 1; l <= v - k - 1; ++l) {
            dp[v][v] = (dp[v][v] + dp[l][l]) % MOD;
        }
    }

    long long ans = 0;
    for (int j = 1; j <= n; ++j) {
        ans = (ans + dp[n][j]) % MOD;
    }

    cout << ans << '\n';

    return 0;
}

