void solve() {
    int n;
    cin >> n;
    string s;
    cin >> s;

    // Special case: string length 1
    if (n == 1) {
        cout << "Bob\n";
        return;
    }

    int max_len = 1, start = 0;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[i - 1]) {
            if (i - start > max_len) {
                max_len = i - start;
                start = i - 1;
            }
        }
    }
    if (n - start > max_len) {
        max_len = n - start;
        start = n - 1;
    }

    // Check if the longest segment is greater than half the length
    if (max_len > n / 2) {
        cout << "Alice\n" << max_len << "\n";
        for (int i = 0; i < max_len; ++i) {
            cout << start - i + 1 << " ";
        }
        cout << "\n";
    } else {
        cout << "Bob\n";
    }
}

