#include <iostream>
using namespace std;

bool isValidMove(int x, int y, int n, int m) {
    return x >= 1 && x <= n && y >= 1 && y <= m;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;

    while (t--) {
        int n, m;
        cin >> n >> m;

        bool found = false;

        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= m; ++j) {
                bool isIsolated = true;

                // Knight moves
                vector<pair<int, int>> knightMoves = {
                    {2, 1}, {2, -1}, {-2, 1}, {-2, -1},
                    {1, 2}, {1, -2}, {-1, 2}, {-1, -2}
                };

                for (auto& move : knightMoves) {
                    int newX = i + move.first;
                    int newY = j + move.second;

                    if (isValidMove(newX, newY, n, m)) {
                        isIsolated = false;
                        break;
                    }
                }

                if (isIsolated) {
                    cout << i << " " << j << "\n";
                    found = true;
                    break;
                }
            }

            if (found) break;
        }

        if (!found) {
            cout << 1 << " " << 1 << "\n"; // Any cell if no isolated found
        }
    }

    return 0;
}

