vll gen_divisors(const vector<pair<ll, int>>& fac) {
    vll divs = {1};
    for (auto& [p, e] : fac) {
        ll cur = 1;
        int sz = (int)divs.size();
        for (int i = 0; i < e; ++i) {
            cur *= p;
            for (int j = 0; j < sz; ++j) {
                divs.pb(divs[j] * cur);
            }
        }
    }
    sort(divs.begin(), divs.end());
    return divs;
}

void solve() {
    int k;
    cin >> k;
    vector<pair<ll, int>> fac(k);
    for (int i = 0; i < k; ++i) {
        cin >> fac[i].first >> fac[i].second;
    }

    auto divs = gen_divisors(fac);
    int dsz = (int)divs.size();

    ll V = 1;
    for (auto& [p, e] : fac) {
        for (int i = 0; i < e; ++i) V *= p;
    }

    ll bestS = LLONG_MAX;
    ll ba = 0, bb = 0, bc = 0;

    for (int i = 0; i < dsz; ++i) {
        ll a = divs[i];
        if (a * a * a > V) break;
        ll rem = V / a;
        ll target = (ll)sqrt((long double)rem);
        int pos = lower_bound(divs.begin(), divs.end(), target) - divs.begin();
        for (int j = pos; j >= 0; --j) {
            ll b = divs[j];
            if (b < a) break;
            if (rem % b == 0) {
                ll c = rem / b;
                if (c >= b) {
                    ll S = 2LL * (a * b + a * c + b * c);
                    if (S < bestS) {
                        bestS = S;
                        ba = a; bb = b; bc = c;
                    }
                }
                break;
            }
        }
        for (int j = pos + 1; j < dsz; ++j) {
            ll b = divs[j];
            if (b > rem / a) break;
            if (rem % b == 0) {
                ll c = rem / b;
                if (c >= b) {
                    ll S = 2LL * (a * b + a * c + b * c);
                    if (S < bestS) {
                        bestS = S;
                        ba = a; bb = b; bc = c;
                    }
                }
                break;
            }
        }
    }

    cout << bestS << ' ' << ba << ' ' << bb << ' ' << bc << '\n';
}

