typedef long long ll;
const int MAX_T = 500;
const ll MAX_V = 1e18;

void solve(const vector<pair<ll, ll>>& factors, ll& min_area, ll& a, ll& b, ll& c) {
    ll V = 1;
    for (auto [p, e] : factors) {
        V *= (ll)p * (ll)p * (ll)p * (ll)e / (ll)(p - 1);
    }

    for (ll x = 1; x * x * x <= V; ++x) {
        if (V % x == 0) {
            ll y = V / x;
            for (ll z = x; z * z <= y; ++z) {
                if (y % z == 0) {
                    ll w = y / z;
                    if (w >= z && x <= z && z <= w) {
                        ll area = 2 * (x * z + z * w + w * x);
                        if (area < min_area || (area == min_area && (x != a || z != b || w != c))) {
                            min_area = area;
                            a = x, b = z, c = w;
                        }
                    }
                }
            }
        }
    }
}

