void build_adj() {
    adj.assign((h+1)*(w+1), vector<int>());
    for (int r = 1; r <= h; ++r) {
        for (int c = 1; c <= w; ++c) {
            if (grid[r-1][c-1] == '.') {
                if (r > 1 && grid[r-2][c-1] == '.') adj[r*(w+1)+c].push_back((r-1)*(w+1)+c);
                if (r < h && grid[r][c-1] == '.') adj[r*(w+1)+c].push_back((r+1)*(w+1)+c);
                if (c > 1 && grid[r-1][c-2] == '.') adj[r*(w+1)+c].push_back(r*(w+1)+(c-1));
                if (c < w && grid[r-1][c] == '.') adj[r*(w+1)+c].push_back(r*(w+1)+(c+1));
            }
        }
    }
}

bool dfs(int u, int mask) {
    if (dp[mask][u]) return true;
    dp[mask][u] = true;
    for (int v : adj[u]) {
        if ((mask & (1LL << v)) != 0) {
            if (dfs(v, mask ^ (1LL << v))) return true;
        }
    }
    return false;
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);

    cin >> h >> w >> q;
    grid.resize(h);
    for (auto& s : grid) cin >> s;

    build_adj();
    dp.assign(1LL<<(h*w), vector<bool>(adj.size()));

    for (int d = 0; d < q; ++d) {
        int k; cin >> k;
        vector<pair<int, int>> tmp(k);
        for (auto& [r, c] : tmp) cin >> r >> c, --r, --c, grid[r][c] = '#';

        build_adj();
        for (int i = 0; i < (1<<adj.size()); ++i) fill(dp[i].begin(), dp[i].end(), false);
        dp[0][1] = true;

        for (int u = 1; u <= adj.size(); ++u) {
            for (int mask = 0; mask < (1<<adj.size()); ++mask) {
                if (dp[mask][u]) {
                    for (int v : adj[u]) {
                        if ((mask & (1LL << v)) != 0) {
                            dp[mask ^ (1LL << v)][v] = true;
                        }
                    }
                }
            }
        }

        bool ans = dfs(adj.back(), (1LL << adj.size()) - 1);
        cout << (ans ? "YES\n" : "NO\n");
        fflush(stdout);
    }

    return 0;
}

