    cin >> l[i] >> r[i];
    --l[i]; --r[i];
    by_len[r[i] - l[i] + 1].pb(i);
  }
  segtree st;
  vector<int> res(n + 1);
  for (int x = n; x >= 1; x--) {
    for (int i : by_len[x]) {
