/*
 * Global rollback buffer and DSU structures.
 * Preserved exactly as in the original solution.
 */
const int N = 400043;
const int BUF = N * 20;

int* where[BUF];
int val[BUF];
int cur = 0;

void change(int& x, int y) {
    val[cur] = x;
    where[cur] = &x;
    x = y;
    cur++;
}

void rollback() {
    cur--;
    (*where[cur]) = val[cur];
}

struct DSU {
    vector<int> p, s;
    int comps;

    int get(int x) {
        if (p[x] == x) return x;
        return get(p[x]);
    }

    void merge(int x, int y) {
        x = get(x);
        y = get(y);
        if (x == y) return;
        change(comps, comps - 1);
        if (s[x] < s[y]) swap(x, y);
        change(p[y], x);
        change(s[x], s[x] + s[y]);
    }

    DSU(int n = 0) {
        s.assign(n, 1);
        p.resize(n);
        iota(p.begin(), p.end(), 0);
        comps = n;
    }
};

struct edge {
