#include <bits/stdc++.h>
using namespace std;

const int MAXN = 400005;

int n, q, parent[MAXN], size[MAXN];

void init(int N) {
    for (int i = 0; i < N; ++i) {
        parent[i] = i;
        size[i] = 1;
    }
}

int find(int x) {
    return (parent[x] == x) ? x : (parent[x] = find(parent[x]));
}

void unite(int x, int y) {
    x = find(x);
    y = find(y);
    if (x != y) {
        if (size[x] > size[y]) swap(x, y);
        parent[x] = y;
        size[y] += size[x];
    }
}

vector<vector<int>> adjA, adjB;

void dfs(vector<vector<int>>& adj, vector<bool>& visited, int u) {
    visited[u] = true;
    for (int v : adj[u]) {
        if (!visited[v]) {
            dfs(adj, visited, v);
        }
    }
}

int getComponents(vector<vector<int>>& adj) {
    vector<bool> visited(n + 1, false);
    int count = 0;
    for (int i = 1; i <= n; ++i) {
        if (!visited[i]) {
            dfs(adj, visited, i);
            ++count;
        }
    }
    return count;
}

void solve() {
    cin >> n >> q;
    adjA.resize(n + 1);
    adjB.resize(n + 1);
    init(n);

    while (q--) {
        char c;
        int x, y;
        cin >> c >> x >> y;

        if (c == 'A') {
            if (find(x) != find(y)) {
                unite(x, y);
                adjA[x].push_back(y);
                adjA[y].push_back(x);
            }
        } else {
            auto& adj = (x == 1 ? adjB : adjA);
            adj[x].erase(remove(adj[x].begin(), adj[x].end(), y), adj[x].end());
            adj[y].erase(remove(adj[y].begin(), adj[y].end(), x), adj[y].end());
        }

        int compA = getComponents(adjA);
        int compB = getComponents(adjB);

        cout << (compA >= compB ? 0 : compB - compA) << '\n';
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
    return 0;
}

