ll gcd(ll a, ll b) {
    while (a > 0) {
        ll temp = b % a;
        b = a;
        a = temp;
    }
    return b;
}

ll lcm(ll a, ll b) {
    return a / gcd(a, b) * b;
}

ll ceildiv(ll n, ll k) {
    ll t = n / k;
    if (n % k == 0) return t;
    return t + 1;
}

ll pw(ll a, ll b) {
    ll r = 1;
    while (b) {
        if (b & 1) r *= a;
        a *= a;
        b >>= 1;
    }
    return r;
}

ll modpw(ll a, ll b, ll mod) {
    ll r = 1 % mod;
    a %= mod;
    while (b) {
        if (b & 1) r = r * a % mod;
        a = a * a % mod;
        b >>= 1;
    }
    return r;
}

