#include <bits/stdc++.h>
using namespace std;

int mad(const vector<int>& a, int len) {
    unordered_map<int, int> count;
    int max_dup = 0;
    for (int i = 0; i < len; ++i) {
        count[a[i]]++;
        if (count[a[i]] >= 2 && a[i] > max_dup) {
            max_dup = a[i];
        }
    }
    return max_dup;
}

void solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    long long sum = 0;
    for (int& x : a) {
        cin >> x;
        sum += x;
    }

    while (true) {
        bool changed = false;
        vector<int> b(n);
        for (int i = 0; i < n; ++i) {
            b[i] = mad(a, i + 1);
            if (b[i] != a[i]) {
                changed = true;
            }
        }
        if (!changed) break;
        for (int i = 0; i < n; ++i) {
            a[i] = b[i];
            sum -= a[i]; // Subtract old value
            sum += a[i]; // Add new value
        }
    }

    cout << sum << '\n';
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) solve();

    return 0;
}
